WITH payload AS (
  SELECT $RISQQ131${"questions":[{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.7","internal_question_no":"13A.007","question_sort_key":13100700.461,"question_text":"If an engine room dead man alarm (personnel alarm) is provided, is it correctly set and in good order?","guide_to_inspection":"The EOOW should report to the bridge whenever entering or leaving an unattended machinery space. On entering the space for\nany reason, they should use the deadman alarm system if fitted.\nOn ships without a deadman alarm, the bridge should be contacted at least once every 15 minutes.\n(Engine Room Procedures Guide 2024)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":199,"source_page_end":199,"raw_source_text":"If an engine room dead man alarm (personnel alarm) is provided, is it correctly set and in good order? (V)\nGuide to Inspection\nThe EOOW should report to the bridge whenever entering or leaving an unattended machinery space. On entering the space for\nany reason, they should use the deadman alarm system if fitted.\nOn ships without a deadman alarm, the bridge should be contacted at least once every 15 minutes.\n(Engine Room Procedures Guide 2024)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.8","internal_question_no":"13A.008","question_sort_key":13100800.462,"question_text":"Is an engineer’s calling alarm system fitted and is it tested regularly, in good order and the results recorded?","guide_to_inspection":"When it is safe and agreeable by the Master, the inspector shall test the engineer call alarm.\nEngineers’ alarm.\nIn addition to manual operation from the machinery space, the engineers’ alarm on vessels with periodically unattended\nmachinery spaces should operate when the machinery alarm is not accepted in the machinery spaces or control room in a\nspecified period of time, e.g., two minutes.\n(Code on alerts and indicators 2009, 2010)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":199,"source_page_end":199,"raw_source_text":"Is an engineer’s calling alarm system fitted and is it tested regularly, in good order and the results recorded? (V)\nGuide to Inspection\nWhen it is safe and agreeable by the Master, the inspector shall test the engineer call alarm.\nEngineers’ alarm.\nIn addition to manual operation from the machinery space, the engineers’ alarm on vessels with periodically unattended\nmachinery spaces should operate when the machinery alarm is not accepted in the machinery spaces or control room in a\nspecified period of time, e.g., two minutes.\n(Code on alerts and indicators 2009, 2010)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.9","internal_question_no":"13A.009","question_sort_key":13100900.463,"question_text":"Is the engine room logbook, as well as other required records being properly maintained?","guide_to_inspection":"Engine room alarm histories are necessary for machinery space inspections and audits to determine management’s level of\ncontrol over engine room activities and to ensure the machinery space has been operated safely and responsibly. Record a\nFinding, if there is evidence that manual logging of alarms is not being undertaken in the absence of an engine room alarm\nlogging printer and if historical records for the last 12 months cannot be provided.\nThe followings should be recorded correctly in the engine logbook:\n> Readings of main propulsion engine\n> Readings of auxiliary engines\n> Readings of other running machineries\n> Main engine RPM and load on the engine\n> Daily entry for all the lube oil ROB\n> Daily entry for all grade of fuel oil ROB\n> ROB value of sludge and bilge\n> Running hour counter for important machinery\n> Record of any major breakdown and reason for the same\n> Record of all bunkering operation (time, place, and quantity)\n> Record of soot blow for the boiler tube (Soot blowing should be performed when the vessel is at sea and/or outside the\nport limit)\n> Record the start and stop times of UMS mode\nThe engineer watch keeper should sign the logbook after completion of watch and the Chief Engineer should sign the logbook\non a daily basis.\nErrors made in the log should be struck through with a single line and initialled and dated. Correction fluid must not be used for\ncorrection of error made in the logbook.\nExamples of required records include the following:\n> Fuel change over log;\n> Cooling water and boiler water logs;\n> Daily fuel and bilge tank sounding log;\n> Fresh water log;\n> Stern tube bearing temperature records;\n> Bio Fouling record book;\n> NOx technical files records, record book of engine parameters;\n> Ozone Depleting Substance(ODS) records;\n> Inventory of hazardous material records;\n> Grey and black water discharge log;\n> Machinery defect log\n> The EOOW should ensure that the alarm printers and automation system are set to the correct time and date at the start of\neach watch. This is critical during inspections and incident investigations to demonstrate compliance.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":199,"source_page_end":199,"raw_source_text":"Is the engine room logbook, as well as other required records being properly maintained? (V)\nGuide to Inspection\nEngine room alarm histories are necessary for machinery space inspections and audits to determine management’s level of\ncontrol over engine room activities and to ensure the machinery space has been operated safely and responsibly. Record a\nFinding, if there is evidence that manual logging of alarms is not being undertaken in the absence of an engine room alarm\nlogging printer and if historical records for the last 12 months cannot be provided.\nThe followings should be recorded correctly in the engine logbook:\n> Readings of main propulsion engine\n> Readings of auxiliary engines\n> Readings of other running machineries\n> Main engine RPM and load on the engine\n> Daily entry for all the lube oil ROB\n> Daily entry for all grade of fuel oil ROB\n> ROB value of sludge and bilge\n> Running hour counter for important machinery\n> Record of any major breakdown and reason for the same\n> Record of all bunkering operation (time, place, and quantity)\n> Record of soot blow for the boiler tube (Soot blowing should be performed when the vessel is at sea and/or outside the\nport limit)\n> Record the start and stop times of UMS mode\nThe engineer watch keeper should sign the logbook after completion of watch and the Chief Engineer should sign the logbook\non a daily basis.\nErrors made in the log should be struck through with a single line and initialled and dated. Correction fluid must not be used for\ncorrection of error made in the logbook.\nExamples of required records include the following:\n> Fuel change over log;\n> Cooling water and boiler water logs;\n> Daily fuel and bilge tank sounding log;\n> Fresh water log;\n> Stern tube bearing temperature records;\n> Bio Fouling record book;\n> NOx technical files records, record book of engine parameters;\n> Ozone Depleting Substance(ODS) records;\n> Inventory of hazardous material records;\n> Grey and black water discharge log;\n> Machinery defect log\n> The EOOW should ensure that the alarm printers and automation system are set to the correct time and date at the start of\neach watch. This is critical during inspections and incident investigations to demonstrate compliance.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.10","internal_question_no":"13A.010","question_sort_key":13101000.464,"question_text":"Are procedures to recover essential equipment documented and posted in the engine room?","guide_to_inspection":"The inspector shall check if the engineers are familiar with the equipment which is shed on the operation of the preferential trip.\nA ship’s specific procedure should be readily available and posted in the engine control room and at the local position near\nequipment which, where applicable, covers the following:\n> Restoring power from the emergency to the main switchboard\n> Charging the air receivers and starting the main diesel generators in order to provide electrical power to all auxiliaries (fuel\nand lubricating oil pumps and the boiler supply)\n> Restarting all auxiliaries\n> Restarting the main engine\nUse of schematic diagram or photograph along with instructions is an example of effective procedure/instructions.\nThe preferential trip is a part of the ship’s generator protection system. It is the electrical arrangement on ships which is designed to\ndisconnect the non-essential circuits (i.e. supplying non-essential load) from the main bus bar in case of partial failure or overload of\nthe main supply. The non-essential circuits or loads on ships are air conditioning, exhaust and ventilation fans, and galley equipment\nwhich can be disconnected momentarily and can be connected again after fault finding. The main advantage of preferential trip is\nthat it helps in preventing the operation of main circuit breaker trip and loss of power on essential services and thus prevents blackout\nand overloading of the generator. The preferential trip operates at timed intervals and the load is removed accordingly. If the overload\npersists, then an audible and visual alarm is sounded. The preferential trip is an important electrical circuit which helps remove\nexcessive load from the main bus bar, thus preventing a blackout.\nThe crew should be familiar with the equipment which is shed on the operation of the preferential trip. This is often a multi-stage\nprocess with first and second stage tripping arranged to shed load. The items are usually indicated on the switchboard to show what\nis shed for each level of trip.\n(Reducing the Risk of Propulsion Loss, 2017)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":200,"source_page_end":200,"raw_source_text":"Are procedures to recover essential equipment documented and posted in the engine room? (V)\nGuide to Inspection\nThe inspector shall check if the engineers are familiar with the equipment which is shed on the operation of the preferential trip.\nA ship’s specific procedure should be readily available and posted in the engine control room and at the local position near\nequipment which, where applicable, covers the following:\n> Restoring power from the emergency to the main switchboard\n> Charging the air receivers and starting the main diesel generators in order to provide electrical power to all auxiliaries (fuel\nand lubricating oil pumps and the boiler supply)\n> Restarting all auxiliaries\n> Restarting the main engine\nUse of schematic diagram or photograph along with instructions is an example of effective procedure/instructions.\nThe preferential trip is a part of the ship’s generator protection system. It is the electrical arrangement on ships which is designed to\ndisconnect the non-essential circuits (i.e. supplying non-essential load) from the main bus bar in case of partial failure or overload of\nthe main supply. The non-essential circuits or loads on ships are air conditioning, exhaust and ventilation fans, and galley equipment\nwhich can be disconnected momentarily and can be connected again after fault finding. The main advantage of preferential trip is\nthat it helps in preventing the operation of main circuit breaker trip and loss of power on essential services and thus prevents blackout\nand overloading of the generator. The preferential trip operates at timed intervals and the load is removed accordingly. If the overload\npersists, then an audible and visual alarm is sounded. The preferential trip is an important electrical circuit which helps remove\nexcessive load from the main bus bar, thus preventing a blackout.\nThe crew should be familiar with the equipment which is shed on the operation of the preferential trip. This is often a multi-stage\nprocess with first and second stage tripping arranged to shed load. The items are usually indicated on the switchboard to show what\nis shed for each level of trip.\n(Reducing the Risk of Propulsion Loss, 2017)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.11","internal_question_no":"13A.011","question_sort_key":13101100.465,"question_text":"Is an effective and up to date planned maintenance system available and being followed on board the vessel?","guide_to_inspection":"RightShip recommends a computer-based planned maintenance system on board the vessel.\nRecord Finding if:\n> The vessel is not equipped with a computer-based planned maintenance system\n> The officers and engineers are not familiar with the use of the software and have not received any familiarisation training.\n> The automatic data feed in almost real time cannot be take place between the vessel and the vessel’s manager.\nThe planned maintenance system is mandatory as per the International Safety Management Code (ISM) Section 10.1. The planned\nmaintenance system (PMS) shall be a paper or software-based system which allows ship owners or the vessel’s manager to carry out\nmaintenance in intervals according to manufacturers and classification society requirements.\nAn effective PMS streamlines the planning, documentation and implementation of maintenance work and surveys on board ship. The\nfollowings minimum requirement shall be incorporated in an effective PMS:\n> The description and documentation of the planned maintenance system are to be in the English language and/or working\nlanguage of the crew\n> Planned maintenance program must include equipment manufacturers’ requirements\n> Inventory content, i.e., items/systems\n> Maintenance time intervals, i.e., time intervals at which the maintenance jobs are to take place\n> Maintenance instructions, i.e., maintenance procedures to be followed\n> Maintenance documentation and history, i.e., documents specifying maintenance jobs carried out and their results\n> Reference documentation, i.e., performance results and measurements taken at certain intervals for trend investigations from\ndelivery stage\n> Document flow chart, i.e., chart showing flow and filling of maintenance documents such as planning cards, job cards etc\n> Signing instructions, i.e., who signs documents for verification of maintenance work carried out\nIn addition to the above, the computerised planned maintenance systems shall provide:\n> A unique login ID and password for each person performing the maintenance/inspection\n> Adequate backup – either backup copy on board or a regular exchange of data between ship and office\n> Automatic Data Transfer – synchronisation of data between the fleet of vessels and ship’s management office using the\nimport/export functionality automatically or manually when required, enabling the vessel’s manager to monitor the status of\nmaintenance on board the ship.\nThe planned maintenance system must be approved when the vessel entered the planned maintenance scheme of a classification\nsociety. A type approval certificate for the software of the planned maintenance system is required.\nIf the is vessel accepted by the classification society for an approved planned maintenance scheme for machinery (PMS), as an\nalternative to the continuous machinery survey (CMS), it considers surveys to be carried out on the basis of intervals between\noverhauls recommended by manufacturers, documented operator’s experience and a condition monitoring system, where fitted.\nAccess to computerized systems for updating the maintenance documentation and maintenance program shall only be permitted\nby the Chief Engineer or other authorised person. A computerised and approved planned maintenance system shall be provided.\nComputerised systems shall include back-up devices, such as CDs which are to be updated at regular intervals.\nCondition Monitoring System:\nMachinery or technical installations, which are subject to a condition monitoring system, shall be surveyed in line with the\nrequirements described in the “Guidelines for Machinery Condition Monitoring” of the classification society. Prerequisite for\nthis special survey arrangement CM is the existence of a computerized planned maintenance system (PMS). The elements\nof the PMS considering the machinery components or part of them covered by condition monitoring shall be approved by the\nclassification society. When a vessel entered the condition monitoring scheme of the classification society, the vessel manager\nshall consider following:\n> The maintenance strategy adopted must be clearly documented in the PMS / SMS – the full scope must be documented\nand fully understood by all engineers and shore-based technical\n> CBM/CBO inspection intervals must be adhered to and proper records must be maintained (measurements, observations,\nclearances, oil/fuel analysis, performance reports and photos)\n> There must be evidence that CBM/CBO reports are factored in to determining predictions of revised next full overhaul\nhours, and these should be clear in the PMS\n> There must be evidence that the maker’s instructions for CBM/CBO strategy are complied with\n> The maker’s associated Service Letters must be readily at hand to support the CBM/CBO strategy as associated reference\nguides\n> There must be objective evidence to show that shore technical are actively involved in the ongoing review of inspection\nrecords/results\n> CMB/CBO does not absolve the ship from maintaining a sufficient number of spare parts on board if overhaul is\nunexpectedly required\nWhen PMS notation was assigned to the vessel, the latest version of the PMS shall be installed on board, and the Type Approval\ncertificate for the specific PMS version should be available on board.\nCritical Equipment and Associated Spare Parts:\nIt is recommended that a proactive risk-based approach to the carriage of safety critical spare parts is taken for the\nmanagement of hazardous situations. This approach may need to be above and beyond minimum regulatory requirements.\nCompanies should apply this approach to both new-builds and to existing vessels.\n(Safety critical equipment and spare parts guidance 2018)\nTo minimize equipment failures, original spares should be used whenever possible. An important part of engine room procedure\nis the storage and upkeep of technical spare parts. A list of critical spares needs to be carried on board and a minimum quantity\nof these spares kept at all times.\nAll members of the engineering team should be trained on how to use spares and consumables properly. Companies can often\nsource spare parts directly from Original Equipment Manufacturer(OEMs) rather than the machinery supplier. However, while this\ncan reduce costs, there is a risk that if the specification of the spares changes, the OEM might not be able to supply the correct\nspares. Companies should be aware of the risk of sourcing spare parts directly from Original Equipment Manufacturer(OEMs)\nrather than the machinery supplier.\n(Engine Room Procedures Guide , 2024)\nThe OCIMF information paper “Safety Criteria Equipment and Spare Parts Guidance” provides further information. Please\ndownload the document via HERE.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":200,"source_page_end":201,"raw_source_text":"Is an effective and up to date planned maintenance system available and being followed on\nboard the vessel? (V & M)\nGuide to Inspection\nRightShip recommends a computer-based planned maintenance system on board the vessel.\nRecord Finding if:\n> The vessel is not equipped with a computer-based planned maintenance system\n> The officers and engineers are not familiar with the use of the software and have not received any familiarisation training.\n> The automatic data feed in almost real time cannot be take place between the vessel and the vessel’s manager.\nThe planned maintenance system is mandatory as per the International Safety Management Code (ISM) Section 10.1. The planned\nmaintenance system (PMS) shall be a paper or software-based system which allows ship owners or the vessel’s manager to carry out\nmaintenance in intervals according to manufacturers and classification society requirements.\nAn effective PMS streamlines the planning, documentation and implementation of maintenance work and surveys on board ship. The\nfollowings minimum requirement shall be incorporated in an effective PMS:\n> The description and documentation of the planned maintenance system are to be in the English language and/or working\nlanguage of the crew\n> Planned maintenance program must include equipment manufacturers’ requirements\n> Inventory content, i.e., items/systems\n> Maintenance time intervals, i.e., time intervals at which the maintenance jobs are to take place\n> Maintenance instructions, i.e., maintenance procedures to be followed\n> Maintenance documentation and history, i.e., documents specifying maintenance jobs carried out and their results\n> Reference documentation, i.e., performance results and measurements taken at certain intervals for trend investigations from\ndelivery stage\n> Document flow chart, i.e., chart showing flow and filling of maintenance documents such as planning cards, job cards etc\n> Signing instructions, i.e., who signs documents for verification of maintenance work carried out\nIn addition to the above, the computerised planned maintenance systems shall provide:\n> A unique login ID and password for each person performing the maintenance/inspection\n> Adequate backup – either backup copy on board or a regular exchange of data between ship and office\n> Automatic Data Transfer – synchronisation of data between the fleet of vessels and ship’s management office using the\nimport/export functionality automatically or manually when required, enabling the vessel’s manager to monitor the status of\nmaintenance on board the ship.\nThe planned maintenance system must be approved when the vessel entered the planned maintenance scheme of a classification\nsociety. A type approval certificate for the software of the planned maintenance system is required.\nIf the is vessel accepted by the classification society for an approved planned maintenance scheme for machinery (PMS), as an\nalternative to the continuous machinery survey (CMS), it considers surveys to be carried out on the basis of intervals between\noverhauls recommended by manufacturers, documented operator’s experience and a condition monitoring system, where fitted.\nAccess to computerized systems for updating the maintenance documentation and maintenance program shall only be permitted\nby the Chief Engineer or other authorised person. A computerised and approved planned maintenance system shall be provided.\nComputerised systems shall include back-up devices, such as CDs which are to be updated at regular intervals.\nCondition Monitoring System:\nMachinery or technical installations, which are subject to a condition monitoring system, shall be surveyed in line with the\nrequirements described in the “Guidelines for Machinery Condition Monitoring” of the classification society. Prerequisite for\nthis special survey arrangement CM is the existence of a computerized planned maintenance system (PMS). The elements\nof the PMS considering the machinery components or part of them covered by condition monitoring shall be approved by the\nclassification society. When a vessel entered the condition monitoring scheme of the classification society, the vessel manager\nshall consider following:\n> The maintenance strategy adopted must be clearly documented in the PMS / SMS – the full scope must be documented\nand fully understood by all engineers and shore-based technical\n> CBM/CBO inspection intervals must be adhered to and proper records must be maintained (measurements, observations,\nclearances, oil/fuel analysis, performance reports and photos)\n> There must be evidence that CBM/CBO reports are factored in to determining predictions of revised next full overhaul\nhours, and these should be clear in the PMS\n> There must be evidence that the maker’s instructions for CBM/CBO strategy are complied with\n> The maker’s associated Service Letters must be readily at hand to support the CBM/CBO strategy as associated reference\nguides\n> There must be objective evidence to show that shore technical are actively involved in the ongoing review of inspection\nrecords/results\n> CMB/CBO does not absolve the ship from maintaining a sufficient number of spare parts on board if overhaul is\nunexpectedly required\nWhen PMS notation was assigned to the vessel, the latest version of the PMS shall be installed on board, and the Type Approval\ncertificate for the specific PMS version should be available on board.\nCritical Equipment and Associated Spare Parts:\nIt is recommended that a proactive risk-based approach to the carriage of safety critical spare parts is taken for the\nmanagement of hazardous situations. This approach may need to be above and beyond minimum regulatory requirements.\nCompanies should apply this approach to both new-builds and to existing vessels.\n(Safety critical equipment and spare parts guidance 2018)\nTo minimize equipment failures, original spares should be used whenever possible. An important part of engine room procedure\nis the storage and upkeep of technical spare parts. A list of critical spares needs to be carried on board and a minimum quantity\nof these spares kept at all times.\nAll members of the engineering team should be trained on how to use spares and consumables properly. Companies can often\nsource spare parts directly from Original Equipment Manufacturer(OEMs) rather than the machinery supplier. However, while this\ncan reduce costs, there is a risk that if the specification of the spares changes, the OEM might not be able to supply the correct\nspares. Companies should be aware of the risk of sourcing spare parts directly from Original Equipment Manufacturer(OEMs)\nrather than the machinery supplier.\n(Engine Room Procedures Guide , 2024)\nThe OCIMF information paper “Safety Criteria Equipment and Spare Parts Guidance” provides further information. Please\ndownload the document via HERE.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.12","internal_question_no":"13A.012","question_sort_key":13101200.466,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":201,"source_page_end":201,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.13","internal_question_no":"13A.013","question_sort_key":13101300.467,"question_text":"Is the main engine maintained as per manufacturer’s recommendations and records of periodic maintenance kept?","guide_to_inspection":"Engineers should be familiar with the utilisation of the override function of engine power limiters. They should also understand\nthat the activation of this override may be necessary while navigating in pilotage waters.\nRandom checks should be made by inspectors to ensure that the periodic maintenance of fuel valve, fuel pump, exhaust valve,\ncylinder cover, pistons, liner, cross head, bottom end, main bearing, turbo charger and governor of the main engine units had\nbeen done as per manufacturer recommendation. The main engine shall appear well maintained and free of any leaks.\nThe watchkeeping team should conduct frequent rounds to check engine operating parameters. Any deviations or abnormalities\nshould be noted, and adjustments made. This includes the temperatures and pressures for fuel oil, lube oil, jacket cooling water\nand scavenge air.\nThe most frequent indicator of engine problems is the exhaust temperature, with high deviation either above or below average,\nalong with abnormal color of the exhaust smoke. Any excessive deviations in the exhaust temperature should be investigated.\nThis is done by using indicator cards or electronic devices to check peak and compression pressures.\nThe engine should be operated within the parameters specified by the manufacturer. Specific guidelines for low load operations\nshould be followed for ships that continuously run on reduced speed.\n(Engine Room Procedures Guide , 2024)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":201,"source_page_end":201,"raw_source_text":"Is the main engine maintained as per manufacturer’s recommendations and records of periodic\nmaintenance kept? (V)\nGuide to Inspection\nEngineers should be familiar with the utilisation of the override function of engine power limiters. They should also understand\nthat the activation of this override may be necessary while navigating in pilotage waters.\nRandom checks should be made by inspectors to ensure that the periodic maintenance of fuel valve, fuel pump, exhaust valve,\ncylinder cover, pistons, liner, cross head, bottom end, main bearing, turbo charger and governor of the main engine units had\nbeen done as per manufacturer recommendation. The main engine shall appear well maintained and free of any leaks.\nThe watchkeeping team should conduct frequent rounds to check engine operating parameters. Any deviations or abnormalities\nshould be noted, and adjustments made. This includes the temperatures and pressures for fuel oil, lube oil, jacket cooling water\nand scavenge air.\nThe most frequent indicator of engine problems is the exhaust temperature, with high deviation either above or below average,\nalong with abnormal color of the exhaust smoke. Any excessive deviations in the exhaust temperature should be investigated.\nThis is done by using indicator cards or electronic devices to check peak and compression pressures.\nThe engine should be operated within the parameters specified by the manufacturer. Specific guidelines for low load operations\nshould be followed for ships that continuously run on reduced speed.\n(Engine Room Procedures Guide , 2024)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.14","internal_question_no":"13A.014","question_sort_key":13101400.468,"question_text":"Are the auxiliary engines maintained as per manufacturer’s recommendations and records of periodic maintenance kept?","guide_to_inspection":"Periodic maintenance intervals recommended by the manufacturer shall be followed.\nRandom checks should be made by inspectors to ensure the periodic maintenance of fuel valve, fuel pump, cylinder cover,\npiston, liner, bottom end, main bearing, and turbo blower of the auxiliary engines had been done as per manufacturer\nrecommendation.\nInspector shall check the engine logbook entries to see that any idle generators had been run recently. The auxiliary engines\nshall appear well maintained and free of any leaks.\nCheck that the automatic switch over arrangements and protection devices such as reverse power relays are in good order.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":202,"source_page_end":202,"raw_source_text":"Are the auxiliary engines maintained as per manufacturer’s recommendations and records of periodic\nmaintenance kept?(V)\nGuide to Inspection\nPeriodic maintenance intervals recommended by the manufacturer shall be followed.\nRandom checks should be made by inspectors to ensure the periodic maintenance of fuel valve, fuel pump, cylinder cover,\npiston, liner, bottom end, main bearing, and turbo blower of the auxiliary engines had been done as per manufacturer\nrecommendation.\nInspector shall check the engine logbook entries to see that any idle generators had been run recently. The auxiliary engines\nshall appear well maintained and free of any leaks.\nCheck that the automatic switch over arrangements and protection devices such as reverse power relays are in good order.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.15","internal_question_no":"13A.015","question_sort_key":13101500.469,"question_text":"Are all areas of the machinery space well illuminated, emergency escape routes clearly marked, unobstructed and are ship’s crew familiar with the escape routes?","guide_to_inspection":"Emergency escape routes should be regularly checked to ensure they are properly marked and clear of obstructions. When an\nescape trunk is fitted, check doors for ease of operation. Door seals should be effective and lighting within the trunk should be\noperational.\nDoors should not normally be locked in port. However, if there are security concerns, the measures to prevent unauthorised\naccess should also ensure that personnel have an escape route.\nLocking arrangements and accessibility to embarkation decks\n1. The escape routes are routes for escape and also for access. Accordingly, the locking arrangement should be such that it\ndoes not obstruct these two objectives (escape and access). Doors along any designated escape routes which require keys to\nunlock them when moving in the direction of escape should not be permitted.\n2. The embarkation deck should be accessible from the open decks to which escapes routes.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":202,"source_page_end":202,"raw_source_text":"Are all areas of the machinery space well illuminated, emergency escape routes clearly marked,\nunobstructed and are ship’s crew familiar with the escape routes? (V)\nGuide to Inspection\nEmergency escape routes should be regularly checked to ensure they are properly marked and clear of obstructions. When an\nescape trunk is fitted, check doors for ease of operation. Door seals should be effective and lighting within the trunk should be\noperational.\nDoors should not normally be locked in port. However, if there are security concerns, the measures to prevent unauthorised\naccess should also ensure that personnel have an escape route.\nLocking arrangements and accessibility to embarkation decks\n1. The escape routes are routes for escape and also for access. Accordingly, the locking arrangement should be such that it\ndoes not obstruct these two objectives (escape and access). Doors along any designated escape routes which require keys to\nunlock them when moving in the direction of escape should not be permitted.\n2. The embarkation deck should be accessible from the open decks to which escapes routes.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.16","internal_question_no":"13A.016","question_sort_key":13101600.47,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":202,"source_page_end":202,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.17","internal_question_no":"13A.017","question_sort_key":13101700.471,"question_text":"Is the emergency equipment tested, in good condition and the result recorded?","guide_to_inspection":"Testing of the emergency generator should be carried out under load at least once every quarter. During the inspection, the\ninspector should ask the accompanying engineer to explain the method used for automatic sequential testing. Please note that this\ntesting is not to be conducted during a RightShip inspection.\nThe emergency fire pump, main fire and foam pumps, emergency air compressor, emergency generator, emergency generator\nswitchboard, emergency steering, emergency stops, engineers’ alarms and bilge pumping system, where applicable, shall be\ntested.\nThe emergency air compressor, if fitted, should be regularly tested to the starting pressure of the diesel generator. The emergency\nair reservoir should be permanently maintained at the required pressure.\nSpecial attention may be paid to the correct operation of the priming device attached to the emergency and main fire pumps. They\nshould also have visible and legible operating instructions.\n(Engine Room Procedures Guide , 2024)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":202,"source_page_end":202,"raw_source_text":"Is the emergency equipment tested, in good condition and the result recorded? (V)\nGuide to Inspection\nTesting of the emergency generator should be carried out under load at least once every quarter. During the inspection, the\ninspector should ask the accompanying engineer to explain the method used for automatic sequential testing. Please note that this\ntesting is not to be conducted during a RightShip inspection.\nThe emergency fire pump, main fire and foam pumps, emergency air compressor, emergency generator, emergency generator\nswitchboard, emergency steering, emergency stops, engineers’ alarms and bilge pumping system, where applicable, shall be\ntested.\nThe emergency air compressor, if fitted, should be regularly tested to the starting pressure of the diesel generator. The emergency\nair reservoir should be permanently maintained at the required pressure.\nSpecial attention may be paid to the correct operation of the priming device attached to the emergency and main fire pumps. They\nshould also have visible and legible operating instructions.\n(Engine Room Procedures Guide , 2024)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.18","internal_question_no":"13A.018","question_sort_key":13101800.472,"question_text":"Are engine room emergency stops for ventilation fans and the closing mechanism of ventilation supply and exhaust ducts clearly marked, in working condition, and do records indicate that they have been regularly tested?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":203,"source_page_end":203,"raw_source_text":"Are engine room emergency stops for ventilation fans and the closing mechanism of ventilation\nsupply and exhaust ducts clearly marked, in working condition, and do records indicate that they\nhave been regularly tested? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.19","internal_question_no":"13A.019","question_sort_key":13101900.473,"question_text":"Are engine exhausts and other hot surfaces effectively shielded against oil spray and are flanges and connections of flammable liquid pipelines adequately protected with guards and spray tape?","guide_to_inspection":"Spray from engine room equipment can be at relatively high pressures and can spray many metres from the source of the leak.\nAlmost invariably there is a hot exhaust or some other hot surface nearby. Typically, these can be at a temperature greater than\nthe auto ignition temperature of the sprayed liquid, resulting in a fire. (Swedishclub.com, 2018)\nSurfaces with temperatures above 220°C which may be impinged as a result of a fuel system failure shall be properly insulated.\nPrecautions shall be taken to prevent any oil that may escape under pressure from any pump, filter, or heater from coming into\ncontact with heated surfaces.\n(SOLAS 74,2020)\nA perfect insulation of all exhaust pipes and other hot surfaces will make an engine room more fire safe.\nWhen installing the spray tape on flanges its width should cover the entire surface of the flange and a minimum of 100 mm on\nboth sides of the pipe joint. This is required to ensure enough adhesive surface strength in case when high pressure expands\ninstalled material.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":203,"source_page_end":203,"raw_source_text":"Are engine exhausts and other hot surfaces effectively shielded against oil spray and are flanges\nand connections of flammable liquid pipelines adequately protected with guards and spray tape? (V)\nGuide to Inspection\nSpray from engine room equipment can be at relatively high pressures and can spray many metres from the source of the leak.\nAlmost invariably there is a hot exhaust or some other hot surface nearby. Typically, these can be at a temperature greater than\nthe auto ignition temperature of the sprayed liquid, resulting in a fire. (Swedishclub.com, 2018)\nSurfaces with temperatures above 220°C which may be impinged as a result of a fuel system failure shall be properly insulated.\nPrecautions shall be taken to prevent any oil that may escape under pressure from any pump, filter, or heater from coming into\ncontact with heated surfaces.\n(SOLAS 74,2020)\nA perfect insulation of all exhaust pipes and other hot surfaces will make an engine room more fire safe.\nWhen installing the spray tape on flanges its width should cover the entire surface of the flange and a minimum of 100 mm on\nboth sides of the pipe joint. This is required to ensure enough adhesive surface strength in case when high pressure expands\ninstalled material.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.20","internal_question_no":"13A.020","question_sort_key":13102000.474,"question_text":"Is the lagging and insulation in good condition and free of oil impregnation?","guide_to_inspection":"Steam and other hot pipes should be lagged properly with the appropriate insulating material, and the lagging should be kept\nclean and free of oil. To avoid energy loss, it is important to keep lagging and insulation in good condition. Additionally, steam\ntraps should be maintained in good condition.\n(Engine Room Procedures Guide , 2024)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":203,"source_page_end":203,"raw_source_text":"Is the lagging and insulation in good condition and free of oil impregnation? (V)\nGuide to Inspection\nSteam and other hot pipes should be lagged properly with the appropriate insulating material, and the lagging should be kept\nclean and free of oil. To avoid energy loss, it is important to keep lagging and insulation in good condition. Additionally, steam\ntraps should be maintained in good condition.\n(Engine Room Procedures Guide , 2024)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.21","internal_question_no":"13A.021","question_sort_key":13102100.475,"question_text":"Are the main engine bearing temperature monitors or crankcase oil mist detector(s) in good condition and tested on a regular basis as specified by the manufacturer, and are engineers familiar with the procedure to follow in the event of oil mist in the crankcase?","guide_to_inspection":"Internal combustion engines of 2,250 kW and above or having cylinders of more than 300 mm bore shall be provided with\ncrankcase oil mist detectors or engine bearing temperature monitors or equivalent devices.\n(SOLAS 74,2020)\nOil mist or vapors coming into contact with heated surfaces, can ignite inside engine crankcases and cause explosions.\nEngineers should be familiar with the procedures to follow if oil mist is detected in crankcase. In this case, the Engine Room\nProcedure Guide’s (First Edition 2024) checklist C6 should be used.\n(Engine Room Procedures Guide , 2024)\nRegardless of if the vessel has a UMS notation assigned, if engine bearing temperature monitors or an Oil Mist Detector is fitted,\nthey should be regularly tested and maintained as per manufacturer instructions and the inspector should satisfy that they are\nin good working order.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":203,"source_page_end":203,"raw_source_text":"Are the main engine bearing temperature monitors or crankcase oil mist detector(s) in good condition and\ntested on a regular basis as specified by the manufacturer, and are engineers familiar with the procedure\nto follow in the event of oil mist in the crankcase? (V)\nGuide to Inspection\nInternal combustion engines of 2,250 kW and above or having cylinders of more than 300 mm bore shall be provided with\ncrankcase oil mist detectors or engine bearing temperature monitors or equivalent devices.\n(SOLAS 74,2020)\nOil mist or vapors coming into contact with heated surfaces, can ignite inside engine crankcases and cause explosions.\nEngineers should be familiar with the procedures to follow if oil mist is detected in crankcase. In this case, the Engine Room\nProcedure Guide’s (First Edition 2024) checklist C6 should be used.\n(Engine Room Procedures Guide , 2024)\nRegardless of if the vessel has a UMS notation assigned, if engine bearing temperature monitors or an Oil Mist Detector is fitted,\nthey should be regularly tested and maintained as per manufacturer instructions and the inspector should satisfy that they are\nin good working order.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.22","internal_question_no":"13A.022","question_sort_key":13102200.476,"question_text":"Were the electrical switchboards surrounded by suitable deck insulation, and was the insulation in good order?","guide_to_inspection":"Insulating matting is required only at the front and rear of switchboards. Individual machinery starter boxes located throughout\nthe machinery space are not classified as switchboards and, as such, do not necessitate the use of insulating matting either in\nfront of or behind them.\nIn certain instances, decks may be constructed from composite insulating materials. Where such materials are employed,\nadditional insulation may not be necessary. In these cases, and where insulating matting is not provided, ship documentation\nshould be available to verify the extent of the composite deck covering and its corresponding safe working voltage.\nThe insulating matting used should be appropriate for the voltage of the switchboard in question. As a minimum standard, it\nshould comply with IEC 61111:2009 Class 0 or an equivalent specification, which provides a safe working voltage of up to 1,000\nvolts. For switchboards operating at voltages exceeding 1,000 volts, matting of a higher classification—such as Class 1, rated for\nup to 7,500 volts—should be used.\nAcceptable evidence of the safe working voltage rating of the deck insulation includes manufacturer certification, appropriate\nmarkings, or other relevant documentation.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":204,"source_page_end":204,"raw_source_text":"Were the electrical switchboards surrounded by suitable deck insulation, and was the insulation in good order? (V)\nGuide to Inspection\nInsulating matting is required only at the front and rear of switchboards. Individual machinery starter boxes located throughout\nthe machinery space are not classified as switchboards and, as such, do not necessitate the use of insulating matting either in\nfront of or behind them.\nIn certain instances, decks may be constructed from composite insulating materials. Where such materials are employed,\nadditional insulation may not be necessary. In these cases, and where insulating matting is not provided, ship documentation\nshould be available to verify the extent of the composite deck covering and its corresponding safe working voltage.\nThe insulating matting used should be appropriate for the voltage of the switchboard in question. As a minimum standard, it\nshould comply with IEC 61111:2009 Class 0 or an equivalent specification, which provides a safe working voltage of up to 1,000\nvolts. For switchboards operating at voltages exceeding 1,000 volts, matting of a higher classification—such as Class 1, rated for\nup to 7,500 volts—should be used.\nAcceptable evidence of the safe working voltage rating of the deck insulation includes manufacturer certification, appropriate\nmarkings, or other relevant documentation.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.23","internal_question_no":"13A.023","question_sort_key":13102300.477,"question_text":"Are the spring-loaded drain valves and gauge glass self-closing valves/cocks being maintained and in good order?","guide_to_inspection":"Self-closing valves are fitted between the lower en d of an oil tank and its gauge glass. The purpose of these valves is to isolate\nthe tank gauge glass from the tank. In normal operation they should be shut and only opened to check the tank contents, after\nwhich they should shut automatically under spring pressure or counterbalance gravity.\nChocks of wood, pieces of wire and purpose-made clamps shall not be used to keep these valves open. Self-closing valves are\nessential safety devices. They should be properly maintained and should never be tampered with.\n(Quick Closing and Self Closing Valves, 2011)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":204,"source_page_end":204,"raw_source_text":"Are the spring-loaded drain valves and gauge glass self-closing valves/cocks being maintained and\nin good order? (V)\nGuide to Inspection\nSelf-closing valves are fitted between the lower en d of an oil tank and its gauge glass. The purpose of these valves is to isolate\nthe tank gauge glass from the tank. In normal operation they should be shut and only opened to check the tank contents, after\nwhich they should shut automatically under spring pressure or counterbalance gravity.\nChocks of wood, pieces of wire and purpose-made clamps shall not be used to keep these valves open. Self-closing valves are\nessential safety devices. They should be properly maintained and should never be tampered with.\n(Quick Closing and Self Closing Valves, 2011)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.24","internal_question_no":"13A.024","question_sort_key":13102400.478,"question_text":"Are the sounding pipes and self-closing sounding devices in good order and closed?","guide_to_inspection":"The ‘deadman’ weight of a self-closing sounding device must not be removed, reversed, or lashed open. If spring-loaded types\nself-closing sounding device are in use, the spring must be fitted.\nSounding rods/tapes or funnels are frequently found to be left inside the open sounding pipe for ease of operation, or for\ndumping of residues back into the tanks via the sounding pipes.\n(Engine Room Sounding Pipes, 2009)\nThe inspector shall record Finding if the above practices are noticed in the engine room.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":204,"source_page_end":204,"raw_source_text":"Are the sounding pipes and self-closing sounding devices in good order and closed?\nGuide to Inspection\nThe ‘deadman’ weight of a self-closing sounding device must not be removed, reversed, or lashed open. If spring-loaded types\nself-closing sounding device are in use, the spring must be fitted.\nSounding rods/tapes or funnels are frequently found to be left inside the open sounding pipe for ease of operation, or for\ndumping of residues back into the tanks via the sounding pipes.\n(Engine Room Sounding Pipes, 2009)\nThe inspector shall record Finding if the above practices are noticed in the engine room.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.25","internal_question_no":"13A.025","question_sort_key":13102500.479,"question_text":"Where moving machinery presents a hazard, is it guarded effectively?","guide_to_inspection":"Correct safety guards should be securely fixed to appliances requiring the m and should be checked for security before starting\nany operation. Such guards should only be removed when the equipment is not operating.\nNo machine should be used when a guard or safety device is missing, incorrectly adjusted or defective, or when it is itself in any\nway faulty. If any defect is identified, the machine should be isolated from its power source until it has been repaired.\n(Code of Safe Working Practices for Merchant Seafarer’s, 2024)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":204,"source_page_end":204,"raw_source_text":"Where moving machinery presents a hazard, is it guarded effectively? (V)\nGuide to Inspection\nCorrect safety guards should be securely fixed to appliances requiring the m and should be checked for security before starting\nany operation. Such guards should only be removed when the equipment is not operating.\nNo machine should be used when a guard or safety device is missing, incorrectly adjusted or defective, or when it is itself in any\nway faulty. If any defect is identified, the machine should be isolated from its power source until it has been repaired.\n(Code of Safe Working Practices for Merchant Seafarer’s, 2024)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.26","internal_question_no":"13A.026","question_sort_key":13102600.48,"question_text":"Is the workshop clean and tidy, and are the engine room workshop tools’ protective guards, shields, and emergency stops in good condition?","guide_to_inspection":"Workshop and bench machines should only be operated by competent personnel. The operator should check a machine every\ntime before use and ensure that all safety guards and devices are in position and operative; that all tool pieces (drill bits, cutting\nblades, etc.) are in good condition, and that the work area is adequately lit and free from clutter.\n(Code of Safe Working Practices for Merchant Seafarer’s, 2024)\nThe absence of protective guards and shields on workshop machinery can cause serious eye or bodily injury not only to\noperators but also other crew members present in the workshop.\nThe guards fitted to the lathe, drill and grinder should be well maintained, transparent and made from impact-resistant material.\nRegular checks on the condition of workshop machinery guards should form part of the shipboard planned maintenance\nsystem.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":205,"source_page_end":205,"raw_source_text":"Is the workshop clean and tidy, and are the engine room workshop tools’ protective guards, shields,\nand emergency stops in good condition? (V)\nGuide to Inspection\nWorkshop and bench machines should only be operated by competent personnel. The operator should check a machine every\ntime before use and ensure that all safety guards and devices are in position and operative; that all tool pieces (drill bits, cutting\nblades, etc.) are in good condition, and that the work area is adequately lit and free from clutter.\n(Code of Safe Working Practices for Merchant Seafarer’s, 2024)\nThe absence of protective guards and shields on workshop machinery can cause serious eye or bodily injury not only to\noperators but also other crew members present in the workshop.\nThe guards fitted to the lathe, drill and grinder should be well maintained, transparent and made from impact-resistant material.\nRegular checks on the condition of workshop machinery guards should form part of the shipboard planned maintenance\nsystem.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.27","internal_question_no":"13A.027","question_sort_key":13102700.481,"question_text":"Is the engine room crane, other lifting equipment, and hydraulic tools inspected, tested, and maintained on a regular basis?","guide_to_inspection":"The engine room crane is subject to annual thorough examination every 12-month period and load test every 5 years, unless\notherwise stated by the ship’s flag administration.\nPortable lifting gear including chain blocks, strops and slings shall be inspected and maintained on a regular basis and record of\nsuch inspection and test should be available on board.\n> The engine room transverse crane beam should be clearly marked in several locations – not only on the travelling beam itself\nand, on the hook, but also on the internal fore and aft ‘I’ beam – so that no matter where you are standing on the engine room\ntop plates the SWL of the equipment is clearly visible.\n> Shackles are by their nature a ‘link’ between two components and therefore play an essential role in terms of safety. They\nshould be marked and stamped with the safe working load (SWL).\n(Lifting equipment – shackles and other loose gear, 2013)\nThe spring-loaded retaining ‘tongue’ of hooks should be in good order.\nA lifting appliance log should be maintained on board.\nHydraulic tools, such as hydraulic jacks and bending machines, are often used in the engine room. They should be throughly\ninspected before use and the correct grade of oil should be topped up to the required level. Hydraulic hoses should be maintained\nin good condition and they should not be twisted or entangled during operation. The pressure gauge installed on hydraulic tools\nshould be calibrated regularly to ensure safe working pressures. The manufacturers’ instruction should be followed.\n(Engine Room Procedures Guide , 2024)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":205,"source_page_end":205,"raw_source_text":"Is the engine room crane, other lifting equipment, and hydraulic tools inspected, tested, and maintained\non a regular basis? (V & M)\nGuide to Inspection\nThe engine room crane is subject to annual thorough examination every 12-month period and load test every 5 years, unless\notherwise stated by the ship’s flag administration.\nPortable lifting gear including chain blocks, strops and slings shall be inspected and maintained on a regular basis and record of\nsuch inspection and test should be available on board.\n> The engine room transverse crane beam should be clearly marked in several locations – not only on the travelling beam itself\nand, on the hook, but also on the internal fore and aft ‘I’ beam – so that no matter where you are standing on the engine room\ntop plates the SWL of the equipment is clearly visible.\n> Shackles are by their nature a ‘link’ between two components and therefore play an essential role in terms of safety. They\nshould be marked and stamped with the safe working load (SWL).\n(Lifting equipment – shackles and other loose gear, 2013)\nThe spring-loaded retaining ‘tongue’ of hooks should be in good order.\nA lifting appliance log should be maintained on board.\nHydraulic tools, such as hydraulic jacks and bending machines, are often used in the engine room. They should be throughly\ninspected before use and the correct grade of oil should be topped up to the required level. Hydraulic hoses should be maintained\nin good condition and they should not be twisted or entangled during operation. The pressure gauge installed on hydraulic tools\nshould be calibrated regularly to ensure safe working pressures. The manufacturers’ instruction should be followed.\n(Engine Room Procedures Guide , 2024)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.28","internal_question_no":"13A.028","question_sort_key":13102800.482,"question_text":"Are all spare parts and loose gear in the machinery spaces, stores and steering compartment properly secured?","guide_to_inspection":"The improper handling of Steel plates, kept as spares for the fabrication and maintenance of a variety of ship components, could\nlead to serious injury or even death.\nIt is essential that the vessel’s manager identifies potentially hazardous manual handling operations, including the development\nand implementation of procedures for the storing, securing and manual handling of spare parts and steel plates. The manual\nhandling of these items must only be performed after a formal risk assessment has been conducted by a trained and competent\nindividual using the company’s approved form, ensuring that records are kept in compliance with procedure.\nPrior to undertaking a manual handling task, RightShip recommends that the vessel manager assess the following four factors:\nTask, Individual, Load, and Environment (TILE) to ensure a thorough evaluation of the task and its associated risk.\nRefer to Section 10 and Annex 10.1 of the latest edition of the UK MCA Code of Safe Working Practices (COSWP), Skull P&I, for\nadditional information, or click here to learn more about TILE.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":205,"source_page_end":205,"raw_source_text":"Are all spare parts and loose gear in the machinery spaces, stores and steering compartment\nproperly secured? (V)\nGuide to Inspection\nThe improper handling of Steel plates, kept as spares for the fabrication and maintenance of a variety of ship components, could\nlead to serious injury or even death.\nIt is essential that the vessel’s manager identifies potentially hazardous manual handling operations, including the development\nand implementation of procedures for the storing, securing and manual handling of spare parts and steel plates. The manual\nhandling of these items must only be performed after a formal risk assessment has been conducted by a trained and competent\nindividual using the company’s approved form, ensuring that records are kept in compliance with procedure.\nPrior to undertaking a manual handling task, RightShip recommends that the vessel manager assess the following four factors:\nTask, Individual, Load, and Environment (TILE) to ensure a thorough evaluation of the task and its associated risk.\nRefer to Section 10 and Annex 10.1 of the latest edition of the UK MCA Code of Safe Working Practices (COSWP), Skull P&I, for\nadditional information, or click here to learn more about TILE.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.29","internal_question_no":"13A.029","question_sort_key":13102900.483,"question_text":"Is the standard of housekeeping in the machinery space and steering gear room satisfactory, are these areas clean, free from obvious leaks, and is the engine room bilge clean and free of oil and sediment?","guide_to_inspection":"Housekeeping in the engine room is critical. Keeping debris from building up in the corners of the main space or machinery flats\neliminates potential fuel. Workshops, spare part storeroom, chemical stores, electrician’s store/workshop should be maintained\nclean. Hydraulic or other types of oil may accumulate in the bilge wells of the steering compartment. Appropriate arrangements\nshould be made for its safe disposal. If overboard discharge valves are installed, they must be securely closed and locked, and\npollution prevention notices should be clearly posted nearby.\nEngine room Bilge:\nThe presence of oil accumulated in bilges or drip trays act as additional fuel to sustain burning and increase the likelihood of the fire\nreaching further areas in the engine room.\nThe bilges, especially in the engine room, should be kept clean and free of oil at all times.\n(Hazards associated with dirty engine room bilges - The Shipowners’ Club, 2018)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":206,"source_page_end":206,"raw_source_text":"Is the standard of housekeeping in the machinery space and steering gear room satisfactory, are these areas\nclean, free from obvious leaks, and is the engine room bilge clean and free of oil and sediment? (V)\nGuide to Inspection\nHousekeeping in the engine room is critical. Keeping debris from building up in the corners of the main space or machinery flats\neliminates potential fuel. Workshops, spare part storeroom, chemical stores, electrician’s store/workshop should be maintained\nclean. Hydraulic or other types of oil may accumulate in the bilge wells of the steering compartment. Appropriate arrangements\nshould be made for its safe disposal. If overboard discharge valves are installed, they must be securely closed and locked, and\npollution prevention notices should be clearly posted nearby.\nEngine room Bilge:\nThe presence of oil accumulated in bilges or drip trays act as additional fuel to sustain burning and increase the likelihood of the fire\nreaching further areas in the engine room.\nThe bilges, especially in the engine room, should be kept clean and free of oil at all times.\n(Hazards associated with dirty engine room bilges - The Shipowners’ Club, 2018)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.30","internal_question_no":"13A.030","question_sort_key":13103000.484,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":206,"source_page_end":206,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.31","internal_question_no":"13A.031","question_sort_key":13103100.485,"question_text":"Is the bilge high level alarm system in good order, regularly tested and are records of test maintained?","guide_to_inspection":"High-level alarms for engine room bilges should be tested at least once daily when the engine room is manned, and prior to\nleaving the engine room in Unmanned Machinery Space (UMS) mode, as part of the pre-UMS checks.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":206,"source_page_end":206,"raw_source_text":"Is the bilge high level alarm system in good order, regularly tested and are records of test maintained? (V)\nGuide to Inspection\nHigh-level alarms for engine room bilges should be tested at least once daily when the engine room is manned, and prior to\nleaving the engine room in Unmanned Machinery Space (UMS) mode, as part of the pre-UMS checks.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.32","internal_question_no":"13A.032","question_sort_key":13103200.486,"question_text":"Are the sea chests, seawater pumps, and associated seawater lines and valves in good working order, with no leaks, hard rust, or temporary repairs?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":206,"source_page_end":206,"raw_source_text":"Are the sea chests, seawater pumps, and associated seawater lines and valves in good working order,\nwith no leaks, hard rust, or temporary repairs?","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.33","internal_question_no":"13A.033","question_sort_key":13103300.487,"question_text":"Is the following machinery/equipment, where applicable, in good order and well maintained? (V) > Shaft generator and emergency generator > Boilers, including waste heat and domestic boilers (Boilers should be operated in automatic mode where the automated boilers are installed) > Boiler safety system and instrumentation > Boiler water safety system > Main and emergency air compressors > Purifiers and fuel oil handling equipment > Stern tube sealing arrangements > Incinerator > Sewage system > Air condition and heating system > Refrigeration plant > Accommodation service systems (i.e., Calorifiers, Portable water equipment, heating etc) > Any other items of machinery, including stand-by machinery. > Burners, tubes, uptakes, exhaust manifolds and spark arrestors. > Engine control console including the control and monitoring system > Steering gear system > Battery maintenance and renewal.","guide_to_inspection":"The inspector should record a finding if boiler or cooling feedwater management, including the maintenance of regular testing\nrecords, is not being conducted.\nFeedwater for Boiler and Cooling Systems\nWater contamination remains a constant threat to boiler and cooling systems. To safeguard system integrity and performance,\ndistilled water should be the standard quality used as feedwater.\nUsing non-distilled or untreated fresh water—containing elevated levels of minerals (e.g. calcium, magnesium, carbonates,\nchlorides) and other contaminants (e.g. dissolved organics and suspended solids)—can lead to serious water-related issues if\nnot addressed promptly through an integrated chemical and operational strategy.\nRisks of Using Non-Distilled or Untreated Water\nBoiler Systems\n> Corrosion: Caused by poor feedwater quality, lack of heating/de-aeration, and inadequate chemical treatment.\n> Scaling: Mineral buildup reduces steam generation efficiency and can result in tube rupture.\n> Carryover: Inadequate water level control or treatment allows contaminants into the steam, causing downstream damage.\nCooling Systems\n> Corrosion: Often due to seawater ingress or absence of proper water treatment.\n> Scaling: Especially detrimental to plate heat exchangers, reducing engine cooling capacity.\n> Biofouling: Microbial growth in closed-loop systems disrupts heat exchange and compromises hygiene.\nUse High-Quality Feedwater: Always use distilled or properly treated water to limit corrosion, scaling, and contamination risks.\nAvoid untreated freshwater or seawater, which may carry harmful minerals and biological agents.\nApply the Correct Chemical Treatment: Use appropriate chemical dosing to manage pH levels, prevent scaling, and inhibit\ncorrosion. Ensure dosing systems are calibrated and tailored to your vessel’s specific needs.\nConduct Regular Monitoring and Testing: Implement daily onboard testing, supported by periodic laboratory analysis. This\nenables early detection of issues such as scale, corrosion, or biofouling, and ensures water chemistry stays within safe\nparameters.\nBoiler Blowdown Procedures\nBoiler blowdown is the process of removing water from an operating boiler to eliminate sediment, chemical concentrations, and\ndissolved solids. This practice is essential for preventing carryover, corrosion, and scaling, thereby ensuring the production of\nhigh-quality steam and maintaining the reliability and longevity of the boiler system.\nTypes of Blowdown:\n1. Bottom Blowdown (Blowoff) : The primary objective of bottom blowdown is to remove sludge and sediment that accumulate\nat the bottom of the boiler. The recommended frequency and duration should be determined in accordance with the guidelines\nprovided by the chemical treatment provider.\n2. Continuous Blowdown (Surface Blowdown / Skimmer) : Continuous blowdown targets the removal of impurities from the\nwater surface. In smaller boilers, this may involve a simple dip tube positioned just below the water level. In larger systems,\na skimmer tube runs the length of the boiler just beneath the surface, with evenly spaced holes to extract water slowly. This\nmethod helps eliminate scum and control the concentration of Total Dissolved Solids (TDS), which can negatively impact boiler\nperformance.\nRecordkeeping and Monitoring:\nTo ensure optimal water treatment and system performance, log sheets for both boiler water and cooling water systems should\nbe maintained either as separate records or within the Engineering Logbook.\nProcedure for Loss of Economizer Water\nThe company should establish a documented procedure outlining the actions to be taken in the event of economizer water loss.\nInspectors should verify that ship-specific procedures for monitoring economizer water levels are clearly documented within the\nvessel manager’s SMS. The procedure should include clearly defined corrective actions to be implemented in the event of water\nloss.\nWaste heat boiler (Economizer): A particularly high-risk event on a ship is an economizer soot fire. The soot fire cannot happen\nin an economizer free of soot deposits.\nThe best way to avoid soot deposits is to soot-blow frequently. This is especially true in ships that are often slow steaming,\nwhich raises the likelihood of soot deposits. Except in emergencies before soot-blowing economizers or boilers the bridge\npermission should be sought.\nExhaust gas inlet and outlet temperature and pressure differential between gas inlet and outlet of the economizer should be\nchecked at least once every watch. The economizer should be isolated and manually cleaned with fresh water if the differential\npressure is observed to be significantly high.\nEconomizers may have bypass arrangements for when the ship is maneuvering or to control steam output. To avoid them\nseizing, the bypass should be tested on a regular basis.\nRefrigeration and air conditioning: MARPOL Annex VI Regulation 21 requires refrigeration systems that use refrigerants that are\nclassified as ozone depleting substances (ODS) to maintain an ODS record book. Any intentional charging or discharge of these\nrefrigerants should take place only from/into approved containers. This includes venting the system to remove any trapped air.\nAll of these details, including any maintenance, should be recorded in the ODS record book.\nIncinerator:\n> Waste oil or sludge should not be incinerated when in ports, harbours or estuaries;\n> Sludge from Exhaust Gas Cleaning System(EGCS) should not be incinerated.\n> Plastics and PVC should only be incinerated in IMO-approved incinerators.\n> A copy of the IMO type approval certificate can be found in the incinerator’s manufacturer manual.\n(Engine Room Procedures Guide , 2024)\nDraining water from the ship’s main air receiver can result in catastrophic injury to humans if the observation window for the air\nreceiver drainage pot explodes as a result of the following design issues:\n1. If the nominal bore of the inlet is greater than the nominal bore of the outlet, or\n2. If the output line of the drain pot becomes clogged,\nThe inspector shall record a Finding if this arrangement is fitted.\nRightShip strongly urges the vessel’s manager to remove the sighting glass totally and replace it with a discreet steel baffle to\ndampen any emulsion blow back\nBattery Maintenance:\nThermal runaway occurs when a battery generates more heat than it can dissipate, often due to overcharging or high\ntemperatures. This can lead to catastrophic failure. Valve Regulated Lead Acid (VRLA) and Absorbed Glass Mat (AGM) batteries\nare particularly prone to this issue, especially with mismatched chargers and poor ventilation. Prolonged float charging also\nincreases the risk.\nIt is important to select the right type of lead acid battery for the intended purpose:\n> Flooded or wet cell batteries contain an electrolyte of sulphuric acid/distilled water and require regular maintenance to retain\nthe correct electrolyte level in the cells. These batteries must be stored upright to prevent leakage. This type of battery is most\nsuitable for installations that utilise float charging in the battery circuit to maintain the charge. The service lifespan is 5 years\nto 7 years.\n> Low maintenance wet cell VRLA batteries have sealed cells with a valve arrangement to release the gases created by\ncharging the battery. The electrolyte level cannot be maintained by topping up. These batteries are most suitable for\nintermittent use where the battery circuit is not maintained by a float charge. The service lifespan is 5 years to 7 years,\nalthough batteries installed in a system using a continuous float charge should be replaced after 2 years of use due to the\nincreased risk of explosion under high discharge loads.\n> Maintenance free gel type VRLA batteries have similar properties to wet cell VRLA batteries and are most suitable for\nintermittent use. Batteries installed in a system using a continuous float charge should be replaced after 2 years of use.\n> Absorbent glass mat (AGM) batteries are a type of VRLA battery. The electrolyte is absorbed and suspended between AGM\nplates to provide extended life and durability.\nThese batteries are designed for intermittent charging use and should be replaced after 2 years if installed in a system using a\ncontinuous float charge. Maintain.\nBatteries are a piece of machinery and require a documented service and maintenance log. The record should individually list\nthe type of battery; where it is located on board; when it entered service; dates and details of any inspections or maintenance\nand, if applicable, what corrective action was taken; and when it is due for replacement.\nHazard : Safe stowage of battery installations is crucial to contain and minimise impact in the event of a fire or explosion. To\nprevent a build-up of gases from the charging process batteries should be kept in a purpose-built, well-ventilated locker in a\ncool, dry location away from the elements. Light fittings in a battery compartment should be corrosion-resistant and flame/\nexplosion-proof.\n(MAIB 2025)\nTo access the ATSB accident report regarding the explosion of the air receiver pot observation window glass—caused by\nexposure to air receiver pressure,click here.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":207,"source_page_end":209,"raw_source_text":"Is the following machinery/equipment, where applicable, in good order and well maintained? (V)\n> Shaft generator and emergency generator\n> Boilers, including waste heat and domestic boilers (Boilers should be operated in automatic\nmode where the automated boilers are installed)\n> Boiler safety system and instrumentation\n> Boiler water safety system\n> Main and emergency air compressors\n> Purifiers and fuel oil handling equipment\n> Stern tube sealing arrangements\n> Incinerator\n> Sewage system\n> Air condition and heating system\n> Refrigeration plant\n> Accommodation service systems (i.e., Calorifiers, Portable water equipment, heating etc)\n> Any other items of machinery, including stand-by machinery.\n> Burners, tubes, uptakes, exhaust manifolds and spark arrestors.\n> Engine control console including the control and monitoring system\n> Steering gear system\n> Battery maintenance and renewal.\nGuide to Inspection\nThe inspector should record a finding if boiler or cooling feedwater management, including the maintenance of regular testing\nrecords, is not being conducted.\nFeedwater for Boiler and Cooling Systems\nWater contamination remains a constant threat to boiler and cooling systems. To safeguard system integrity and performance,\ndistilled water should be the standard quality used as feedwater.\nUsing non-distilled or untreated fresh water—containing elevated levels of minerals (e.g. calcium, magnesium, carbonates,\nchlorides) and other contaminants (e.g. dissolved organics and suspended solids)—can lead to serious water-related issues if\nnot addressed promptly through an integrated chemical and operational strategy.\nRisks of Using Non-Distilled or Untreated Water\nBoiler Systems\n> Corrosion: Caused by poor feedwater quality, lack of heating/de-aeration, and inadequate chemical treatment.\n> Scaling: Mineral buildup reduces steam generation efficiency and can result in tube rupture.\n> Carryover: Inadequate water level control or treatment allows contaminants into the steam, causing downstream damage.\nCooling Systems\n> Corrosion: Often due to seawater ingress or absence of proper water treatment.\n> Scaling: Especially detrimental to plate heat exchangers, reducing engine cooling capacity.\n> Biofouling: Microbial growth in closed-loop systems disrupts heat exchange and compromises hygiene.\nUse High-Quality Feedwater: Always use distilled or properly treated water to limit corrosion, scaling, and contamination risks.\nAvoid untreated freshwater or seawater, which may carry harmful minerals and biological agents.\nApply the Correct Chemical Treatment: Use appropriate chemical dosing to manage pH levels, prevent scaling, and inhibit\ncorrosion. Ensure dosing systems are calibrated and tailored to your vessel’s specific needs.\nConduct Regular Monitoring and Testing: Implement daily onboard testing, supported by periodic laboratory analysis. This\nenables early detection of issues such as scale, corrosion, or biofouling, and ensures water chemistry stays within safe\nparameters.\nBoiler Blowdown Procedures\nBoiler blowdown is the process of removing water from an operating boiler to eliminate sediment, chemical concentrations, and\ndissolved solids. This practice is essential for preventing carryover, corrosion, and scaling, thereby ensuring the production of\nhigh-quality steam and maintaining the reliability and longevity of the boiler system.\nTypes of Blowdown:\n1. Bottom Blowdown (Blowoff) : The primary objective of bottom blowdown is to remove sludge and sediment that accumulate\nat the bottom of the boiler. The recommended frequency and duration should be determined in accordance with the guidelines\nprovided by the chemical treatment provider.\n2. Continuous Blowdown (Surface Blowdown / Skimmer) : Continuous blowdown targets the removal of impurities from the\nwater surface. In smaller boilers, this may involve a simple dip tube positioned just below the water level. In larger systems,\na skimmer tube runs the length of the boiler just beneath the surface, with evenly spaced holes to extract water slowly. This\nmethod helps eliminate scum and control the concentration of Total Dissolved Solids (TDS), which can negatively impact boiler\nperformance.\nRecordkeeping and Monitoring:\nTo ensure optimal water treatment and system performance, log sheets for both boiler water and cooling water systems should\nbe maintained either as separate records or within the Engineering Logbook.\nProcedure for Loss of Economizer Water\nThe company should establish a documented procedure outlining the actions to be taken in the event of economizer water loss.\nInspectors should verify that ship-specific procedures for monitoring economizer water levels are clearly documented within the\nvessel manager’s SMS. The procedure should include clearly defined corrective actions to be implemented in the event of water\nloss.\nWaste heat boiler (Economizer): A particularly high-risk event on a ship is an economizer soot fire. The soot fire cannot happen\nin an economizer free of soot deposits.\nThe best way to avoid soot deposits is to soot-blow frequently. This is especially true in ships that are often slow steaming,\nwhich raises the likelihood of soot deposits. Except in emergencies before soot-blowing economizers or boilers the bridge\npermission should be sought.\nExhaust gas inlet and outlet temperature and pressure differential between gas inlet and outlet of the economizer should be\nchecked at least once every watch. The economizer should be isolated and manually cleaned with fresh water if the differential\npressure is observed to be significantly high.\nEconomizers may have bypass arrangements for when the ship is maneuvering or to control steam output. To avoid them\nseizing, the bypass should be tested on a regular basis.\nRefrigeration and air conditioning: MARPOL Annex VI Regulation 21 requires refrigeration systems that use refrigerants that are\nclassified as ozone depleting substances (ODS) to maintain an ODS record book. Any intentional charging or discharge of these\nrefrigerants should take place only from/into approved containers. This includes venting the system to remove any trapped air.\nAll of these details, including any maintenance, should be recorded in the ODS record book.\nIncinerator:\n> Waste oil or sludge should not be incinerated when in ports, harbours or estuaries;\n> Sludge from Exhaust Gas Cleaning System(EGCS) should not be incinerated.\n> Plastics and PVC should only be incinerated in IMO-approved incinerators.\n> A copy of the IMO type approval certificate can be found in the incinerator’s manufacturer manual.\n(Engine Room Procedures Guide , 2024)\nDraining water from the ship’s main air receiver can result in catastrophic injury to humans if the observation window for the air\nreceiver drainage pot explodes as a result of the following design issues:\n1. If the nominal bore of the inlet is greater than the nominal bore of the outlet, or\n2. If the output line of the drain pot becomes clogged,\nThe inspector shall record a Finding if this arrangement is fitted.\nRightShip strongly urges the vessel’s manager to remove the sighting glass totally and replace it with a discreet steel baffle to\ndampen any emulsion blow back\nBattery Maintenance:\nThermal runaway occurs when a battery generates more heat than it can dissipate, often due to overcharging or high\ntemperatures. This can lead to catastrophic failure. Valve Regulated Lead Acid (VRLA) and Absorbed Glass Mat (AGM) batteries\nare particularly prone to this issue, especially with mismatched chargers and poor ventilation. Prolonged float charging also\nincreases the risk.\nIt is important to select the right type of lead acid battery for the intended purpose:\n> Flooded or wet cell batteries contain an electrolyte of sulphuric acid/distilled water and require regular maintenance to retain\nthe correct electrolyte level in the cells. These batteries must be stored upright to prevent leakage. This type of battery is most\nsuitable for installations that utilise float charging in the battery circuit to maintain the charge. The service lifespan is 5 years\nto 7 years.\n> Low maintenance wet cell VRLA batteries have sealed cells with a valve arrangement to release the gases created by\ncharging the battery. The electrolyte level cannot be maintained by topping up. These batteries are most suitable for\nintermittent use where the battery circuit is not maintained by a float charge. The service lifespan is 5 years to 7 years,\nalthough batteries installed in a system using a continuous float charge should be replaced after 2 years of use due to the\nincreased risk of explosion under high discharge loads.\n> Maintenance free gel type VRLA batteries have similar properties to wet cell VRLA batteries and are most suitable for\nintermittent use. Batteries installed in a system using a continuous float charge should be replaced after 2 years of use.\n> Absorbent glass mat (AGM) batteries are a type of VRLA battery. The electrolyte is absorbed and suspended between AGM\nplates to provide extended life and durability.\nThese batteries are designed for intermittent charging use and should be replaced after 2 years if installed in a system using a\ncontinuous float charge. Maintain.\nBatteries are a piece of machinery and require a documented service and maintenance log. The record should individually list\nthe type of battery; where it is located on board; when it entered service; dates and details of any inspections or maintenance\nand, if applicable, what corrective action was taken; and when it is due for replacement.\nHazard : Safe stowage of battery installations is crucial to contain and minimise impact in the event of a fire or explosion. To\nprevent a build-up of gases from the charging process batteries should be kept in a purpose-built, well-ventilated locker in a\ncool, dry location away from the elements. Light fittings in a battery compartment should be corrosion-resistant and flame/\nexplosion-proof.\n(MAIB 2025)\nTo access the ATSB accident report regarding the explosion of the air receiver pot observation window glass—caused by\nexposure to air receiver pressure,click here.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.34","internal_question_no":"13A.034","question_sort_key":13103400.488,"question_text":"Is the pipe work in the machinery space, including but not limited to steam, fuel, lubricating oil, sewage, drain and air lines well maintained, in good condition and free of temporary repair and leakage?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":209,"source_page_end":209,"raw_source_text":"Is the pipe work in the machinery space, including but not limited to steam, fuel, lubricating oil,\nsewage, drain and air lines well maintained, in good condition and free of temporary repair and leakage? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.35","internal_question_no":"13A.035","question_sort_key":13103500.489,"question_text":"Are engineers familiar with operation of the main engine from the local manoeuvring control position?","guide_to_inspection":"Record the date of last drill in comments.\nAll members of the engineering team should be trained and proficient in the local and emergency procedures for starting and\nmaneuvering the main engine. Periodic drills will help to maintain this proficiency. Clear instructions on this procedures should\nbe posted next to the manual/emergency starting and maneuvering stations.\n(Engine Room Procedures Guide , 2024)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":209,"source_page_end":209,"raw_source_text":"Are engineers familiar with operation of the main engine from the local manoeuvring control position? (V)\nGuide to Inspection\nRecord the date of last drill in comments.\nAll members of the engineering team should be trained and proficient in the local and emergency procedures for starting and\nmaneuvering the main engine. Periodic drills will help to maintain this proficiency. Clear instructions on this procedures should\nbe posted next to the manual/emergency starting and maneuvering stations.\n(Engine Room Procedures Guide , 2024)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.36","internal_question_no":"13A.036","question_sort_key":13103600.49,"question_text":"Are crew familiar with the starting procedure for the emergency generator and how to put power on the emergency switch board?","guide_to_inspection":"When agreeable by the Chief Engineer and safe to do so, the inspector shall witness the running test(but not onload) of the\nemergency generator.\nSOLAS II-1/Reg.43.7 requires that provisions for the testing of the emergency source of electrical power, including its automatic\nstarting arrangement, are to be made. Such testing can be conducted using a test switch provided in the Emergency Switch\nBoard (ESB) that enables automatic starting and connecting of the emergency generator to the ESB during simulated blackout\nconditions, in general.\nIt is recommended that tests to ensure automatic starting as well as connecting of the emergency generator to the ESB shall be\ncarried out at appropriate intervals using the test switch in the ESB.\n(Operation test for automatic starting arrangement of emergency generator (Blackout simulation test), 2018)\nInspector shall review of the suitable evidence of such test onboard and question the engineer to explain the process of\nsequential test start and loading of the ESB.\nAll crew members must be familiar with starting procedure of the emergency generator.\nEach emergency generating set arranged to be automatically started shall be equipped with starting devices approved by the\nAdministration with a stored energy capability of at least three consecutive starts. A second source of energy shall be provided\nfor an additional three starts within 30 minutes unless manual starting can be demonstrated to be effective.\n(SOLAS 74,2020)\nThe brief instruction should be simple, clear, and understandable by all crew. The instruction shall incorporate how to put power\non the emergency switch board, if the system is not automatic.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":209,"source_page_end":209,"raw_source_text":"Are crew familiar with the starting procedure for the emergency generator and how to put power\non the emergency switch board? (V)\nGuide to Inspection\nWhen agreeable by the Chief Engineer and safe to do so, the inspector shall witness the running test(but not onload) of the\nemergency generator.\nSOLAS II-1/Reg.43.7 requires that provisions for the testing of the emergency source of electrical power, including its automatic\nstarting arrangement, are to be made. Such testing can be conducted using a test switch provided in the Emergency Switch\nBoard (ESB) that enables automatic starting and connecting of the emergency generator to the ESB during simulated blackout\nconditions, in general.\nIt is recommended that tests to ensure automatic starting as well as connecting of the emergency generator to the ESB shall be\ncarried out at appropriate intervals using the test switch in the ESB.\n(Operation test for automatic starting arrangement of emergency generator (Blackout simulation test), 2018)\nInspector shall review of the suitable evidence of such test onboard and question the engineer to explain the process of\nsequential test start and loading of the ESB.\nAll crew members must be familiar with starting procedure of the emergency generator.\nEach emergency generating set arranged to be automatically started shall be equipped with starting devices approved by the\nAdministration with a stored energy capability of at least three consecutive starts. A second source of energy shall be provided\nfor an additional three starts within 30 minutes unless manual starting can be demonstrated to be effective.\n(SOLAS 74,2020)\nThe brief instruction should be simple, clear, and understandable by all crew. The instruction shall incorporate how to put power\non the emergency switch board, if the system is not automatic.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.37","internal_question_no":"13A.037","question_sort_key":13103700.491,"question_text":"If the starting source of the emergency generator relies on a single starter motor, has a spare starter motor been provided?","guide_to_inspection":"RightShip recommends that a spare starter motor be provided if the starting source relies on that one starter motor. The spare\nstarter motor should be tested quarterly to ensure operational readiness.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":210,"source_page_end":210,"raw_source_text":"If the starting source of the emergency generator relies on a single starter motor, has a spare\nstarter motor been provided? (V)\nGuide to Inspection\nRightShip recommends that a spare starter motor be provided if the starting source relies on that one starter motor. The spare\nstarter motor should be tested quarterly to ensure operational readiness.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.38","internal_question_no":"13A.038","question_sort_key":13103800.492,"question_text":"If an emergency generator is not fitted, are engine room emergency batteries in good order, fully charged and capable of supplying the designed power load up to a minimum 18 hours?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":210,"source_page_end":210,"raw_source_text":"If an emergency generator is not fitted, are engine room emergency batteries in good order, fully\ncharged and capable of supplying the designed power load up to a minimum 18 hours? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.39","internal_question_no":"13A.039","question_sort_key":13103900.493,"question_text":"Is the main and emergency switchboard earth fault monitoring equipment operational with no earthing faults indicated?","guide_to_inspection":"Minimum insulation resistance as per classification society requirements is 1 megohm. It is good practice to maintain the\ninsulation resistance more than 5 megohms for 440 system and 2 megohms for a 220 Volte system. Alarm settings should be\n0.2 MOhm for 220V systems and 0.5 MOhm for 440V systems. This meets the minimum insulation resistance requirement for\n1000 Ohm per Volt.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":210,"source_page_end":210,"raw_source_text":"Is the main and emergency switchboard earth fault monitoring equipment operational with no earthing\nfaults indicated? (V)\nGuide to Inspection\nMinimum insulation resistance as per classification society requirements is 1 megohm. It is good practice to maintain the\ninsulation resistance more than 5 megohms for 440 system and 2 megohms for a 220 Volte system. Alarm settings should be\n0.2 MOhm for 220V systems and 0.5 MOhm for 440V systems. This meets the minimum insulation resistance requirement for\n1000 Ohm per Volt.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.40","internal_question_no":"13A.040","question_sort_key":13104000.494,"question_text":"Is an emergency steering gear drill being carried out every three months?","guide_to_inspection":"Emergency steering drills shall take place at least once every three months in order to practice emergency steering procedures.\nThese drills shall include direct control within the steering gear compartment, the communications procedure with the\nnavigation bridge and, where applicable, the operation of alternative power supplies.\nSimple operating instructions with a block diagram showing the change-over procedures for remote control systems and\nsteering gear power units shall be permanently displayed on the navigation bridge and in the steering gear compartment.\n(SOLAS 74,2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":210,"source_page_end":210,"raw_source_text":"Is an emergency steering gear drill being carried out every three months? (V)\nGuide to Inspection\nEmergency steering drills shall take place at least once every three months in order to practice emergency steering procedures.\nThese drills shall include direct control within the steering gear compartment, the communications procedure with the\nnavigation bridge and, where applicable, the operation of alternative power supplies.\nSimple operating instructions with a block diagram showing the change-over procedures for remote control systems and\nsteering gear power units shall be permanently displayed on the navigation bridge and in the steering gear compartment.\n(SOLAS 74,2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.41","internal_question_no":"13A.041","question_sort_key":13104100.495,"question_text":"Is the emergency reserve tank of the steering gear system fully charged and is the manual transfer pump operational??","guide_to_inspection":"A fixed storage tank shall be provided having sufficient capacity to recharge at least one power actuating system including the\nreservoir.\n(SOLAS 74,2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":210,"source_page_end":210,"raw_source_text":"Is the emergency reserve tank of the steering gear system fully charged and is the manual transfer\npump operational?? (V)\nGuide to Inspection\nA fixed storage tank shall be provided having sufficient capacity to recharge at least one power actuating system including the\nreservoir.\n(SOLAS 74,2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.42","internal_question_no":"13A.042","question_sort_key":13104200.496,"question_text":"Is a heading indicator and communication system provided in the steering gear room and are they in good order?","guide_to_inspection":"Ships with emergency steering positions shall at least be provided with a telephone or other means of communication for\nrelaying heading information to such positions.\n(SOLAS 74,2020)\nIn addition, ships of 500 GT and upwards constructed after 1st February 1992 shall be provided with arrangements for supplying\nvisual compass readings to the emergency steering position.\n(SOLAS 74,2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":210,"source_page_end":210,"raw_source_text":"Is a heading indicator and communication system provided in the steering gear room and are\nthey in good order? (V)\nGuide to Inspection\nShips with emergency steering positions shall at least be provided with a telephone or other means of communication for\nrelaying heading information to such positions.\n(SOLAS 74,2020)\nIn addition, ships of 500 GT and upwards constructed after 1st February 1992 shall be provided with arrangements for supplying\nvisual compass readings to the emergency steering position.\n(SOLAS 74,2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.43","internal_question_no":"13A.043","question_sort_key":13104300.497,"question_text":"Is the rudder angle indicator at the emergency steering position in good order, and is the display clearly legible?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":211,"source_page_end":211,"raw_source_text":"Is the rudder angle indicator at the emergency steering position in good order, and is the display clearly legible? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.44","internal_question_no":"13A.044","question_sort_key":13104400.498,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":211,"source_page_end":211,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"13A","section_number":13,"section_letter":"A","section_title":"Machinery Space","printed_question_no":"13.45","internal_question_no":"13A.045","question_sort_key":13104500.499,"question_text":"Are suitable handrails, gratings or other non-slip surfaces provided for the steering gear compartment?","guide_to_inspection":"The steering gear compartment shall be provided with suitable arrangements to ensure working access to steering gear\nmachinery and controls. These arrangements shall include handrails and gratings or other nonslip surfaces to ensure suitable\nworking conditions in the event of hydraulic fluid leakage.\n(SOLAS 74,2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":211,"source_page_end":211,"raw_source_text":"Are suitable handrails, gratings or other non-slip surfaces provided for the steering gear compartment? (V)\nGuide to Inspection\nThe steering gear compartment shall be provided with suitable arrangements to ensure working access to steering gear\nmachinery and controls. These arrangements shall include handrails and gratings or other nonslip surfaces to ensure suitable\nworking conditions in the event of hydraulic fluid leakage.\n(SOLAS 74,2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"14A","section_number":14,"section_letter":"A","section_title":"General Appearance - Hull and Superstructure","printed_question_no":"14.1","internal_question_no":"14A.001","question_sort_key":14100100.5,"question_text":"Is the ship’s hull clean, free of significant corrosion, extensive coating breakdown and marine growth?","guide_to_inspection":"Implementing practices to control and manage biofouling can greatly assist in reducing the risk of the transfer of invasive\naquatic species.\nSuch management practices can also improve a ship’s hydrodynamic performance and can be effective tools in enhancing\nenergy efficiency and reducing air emissions from ships. This concept has been identified by the IMO in the “Guidance for the\ndevelopment of a ship energy efficiency management plan (SEEMP).\nHull resistance can be optimized by new technology-coating systems, possibly in combination with cleaning intervals. Regular\nin-water inspection of the condition of the hull is recommended.\n(GUIDANCE FOR THE DEVELOPMENT OF A SHIP ENERGY\nEFFICIENCY MANAGEMENT PLAN (SEEMP), 2009)\nThe vessel should be provided with effective, environmentally safe, and practical biofouling management procedures that are\nbased on industry recommendations for in-water cleaning of the ship’s hull to reduce the spread of invasive aquatic species.\nThe vessel is required to maintain a Biofouling Record Book in which all inspections and biofouling management measures are\nrecorded.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":212,"source_page_end":212,"raw_source_text":"Is the ship’s hull clean, free of significant corrosion, extensive coating breakdown and marine growth? (V)\nGuide to Inspection\nImplementing practices to control and manage biofouling can greatly assist in reducing the risk of the transfer of invasive\naquatic species.\nSuch management practices can also improve a ship’s hydrodynamic performance and can be effective tools in enhancing\nenergy efficiency and reducing air emissions from ships. This concept has been identified by the IMO in the “Guidance for the\ndevelopment of a ship energy efficiency management plan (SEEMP).\nHull resistance can be optimized by new technology-coating systems, possibly in combination with cleaning intervals. Regular\nin-water inspection of the condition of the hull is recommended.\n(GUIDANCE FOR THE DEVELOPMENT OF A SHIP ENERGY\nEFFICIENCY MANAGEMENT PLAN (SEEMP), 2009)\nThe vessel should be provided with effective, environmentally safe, and practical biofouling management procedures that are\nbased on industry recommendations for in-water cleaning of the ship’s hull to reduce the spread of invasive aquatic species.\nThe vessel is required to maintain a Biofouling Record Book in which all inspections and biofouling management measures are\nrecorded.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"14A","section_number":14,"section_letter":"A","section_title":"General Appearance - Hull and Superstructure","printed_question_no":"14.2","internal_question_no":"14A.002","question_sort_key":14100200.501,"question_text":"Are the following permanent markings on the ship’s hull, where applicable, plainly visible and painted in a contrasting colour? (V) > The vessel’s name > Port of registry > Load lines > Draft marks > Thruster warnings > Tug push points > IMO number > Bulbous bow mark","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":212,"source_page_end":212,"raw_source_text":"Are the following permanent markings on the ship’s hull, where applicable, plainly visible and\npainted in a contrasting colour? (V)\n> The vessel’s name\n> Port of registry\n> Load lines\n> Draft marks\n> Thruster warnings\n> Tug push points\n> IMO number\n> Bulbous bow mark","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"14A","section_number":14,"section_letter":"A","section_title":"General Appearance - Hull and Superstructure","printed_question_no":"14.3","internal_question_no":"14A.003","question_sort_key":14100300.502,"question_text":"Are the weather decks free of loose rust scale and maintained in a satisfactory condition?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":212,"source_page_end":212,"raw_source_text":"Are the weather decks free of loose rust scale and maintained in a satisfactory condition? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"14A","section_number":14,"section_letter":"A","section_title":"General Appearance - Hull and Superstructure","printed_question_no":"14.4","internal_question_no":"14A.004","question_sort_key":14100400.503,"question_text":"Are the pipes on deck free of significant corrosion, pitting, soft patches, leakage or temporary repair and maintained in good condition?","guide_to_inspection":"The following deck pipes should be checked for external indications of corrosion, pitting and temporary repair:\n> Hydraulic and pneumatic pipework\n> Fire mains and associated fittings\n> Pneumatic lines\n> Electrical conduit lines\n> Ballast lines\n> Fresh water line\n> Steam pipe including heating system\nPipe securing arrangements should be maintained in good condition and allow free movement of the pipes, as necessary.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":212,"source_page_end":212,"raw_source_text":"Are the pipes on deck free of significant corrosion, pitting, soft patches, leakage or temporary repair and\nmaintained in good condition? (V)\nGuide to Inspection\nThe following deck pipes should be checked for external indications of corrosion, pitting and temporary repair:\n> Hydraulic and pneumatic pipework\n> Fire mains and associated fittings\n> Pneumatic lines\n> Electrical conduit lines\n> Ballast lines\n> Fresh water line\n> Steam pipe including heating system\nPipe securing arrangements should be maintained in good condition and allow free movement of the pipes, as necessary.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"14A","section_number":14,"section_letter":"A","section_title":"General Appearance - Hull and Superstructure","printed_question_no":"14.5","internal_question_no":"14A.005","question_sort_key":14100500.504,"question_text":"Are all watertight doors (where fitted), fire doors, weathertight doors, portholes and wheelhouse windows maintained in good order?","guide_to_inspection":"Fire-resistant divisions constructed in accordance with SOLAS II-2 are utilized to contain the fire and reduce the risk of fire\nspread. These divisions’ openings, such as engine room access doors, are equipped with self-closing devices. Fire doors should\nnot be fastened or wedged open in any way.\nDoors positioned on a weather deck, particularly the main deck, are also critical to the vessel’s safety. As a result, they should\nnever be fastened or tied open when underway.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":213,"source_page_end":213,"raw_source_text":"Are all watertight doors (where fitted), fire doors, weathertight doors, portholes and wheelhouse\nwindows maintained in good order? (V)\nGuide to Inspection\nFire-resistant divisions constructed in accordance with SOLAS II-2 are utilized to contain the fire and reduce the risk of fire\nspread. These divisions’ openings, such as engine room access doors, are equipped with self-closing devices. Fire doors should\nnot be fastened or wedged open in any way.\nDoors positioned on a weather deck, particularly the main deck, are also critical to the vessel’s safety. As a result, they should\nnever be fastened or tied open when underway.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"14A","section_number":14,"section_letter":"A","section_title":"General Appearance - Hull and Superstructure","printed_question_no":"14.6","internal_question_no":"14A.006","question_sort_key":14100600.505,"question_text":"Are the vents and air pipes on weather decks maintained in good order and are they clearly marked to indicate the compartment they serve?","guide_to_inspection":"Vent head should be maintained in good condition. The flame screen, if fitted, should be clean and in good condition. The closing\ndevice which prevents the ingress of water into the space through the vent head should be in good condition and operating\ncorrectly.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":213,"source_page_end":213,"raw_source_text":"Are the vents and air pipes on weather decks maintained in good order and are they clearly\nmarked to indicate the compartment they serve? (V)\nGuide to Inspection\nVent head should be maintained in good condition. The flame screen, if fitted, should be clean and in good condition. The closing\ndevice which prevents the ingress of water into the space through the vent head should be in good condition and operating\ncorrectly.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"14A","section_number":14,"section_letter":"A","section_title":"General Appearance - Hull and Superstructure","printed_question_no":"14.7","internal_question_no":"14A.007","question_sort_key":14100700.506,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":213,"source_page_end":213,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"14A","section_number":14,"section_letter":"A","section_title":"General Appearance - Hull and Superstructure","printed_question_no":"14.8","internal_question_no":"14A.008","question_sort_key":14100800.507,"question_text":"Are the hatch numbers clearly indicated and correctly placed?","guide_to_inspection":"The ship shall be provided with the hatch identification numbers used in the loading manual and loading or unloading plan. The\nlocation, size and colour of these numbers should be chosen so that they are clearly visible to the operator of the loading or\nunloading equipment.\n(BLU Code, 2011)\nCargo spaces to be included in the computation of net tonnage are enclosed spaces appropriated for the transport of cargo,\nwhich is to be discharged from the ship, provided that such spaces have been included in the computation of gross tonnage.\nSuch cargo spaces shall be certified by permanent marking with the letters CC (Cargo Compartment) to be so positioned that\nthey are readily visible and not to be less than 4 inches in height.\n(International Convention on Load Lines (1966). Protocols and Organization, 2005)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":213,"source_page_end":213,"raw_source_text":"Are the hatch numbers clearly indicated and correctly placed? (V)\nGuide to Inspection\nThe ship shall be provided with the hatch identification numbers used in the loading manual and loading or unloading plan. The\nlocation, size and colour of these numbers should be chosen so that they are clearly visible to the operator of the loading or\nunloading equipment.\n(BLU Code, 2011)\nCargo spaces to be included in the computation of net tonnage are enclosed spaces appropriated for the transport of cargo,\nwhich is to be discharged from the ship, provided that such spaces have been included in the computation of gross tonnage.\nSuch cargo spaces shall be certified by permanent marking with the letters CC (Cargo Compartment) to be so positioned that\nthey are readily visible and not to be less than 4 inches in height.\n(International Convention on Load Lines (1966). Protocols and Organization, 2005)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"14A","section_number":14,"section_letter":"A","section_title":"General Appearance - Hull and Superstructure","printed_question_no":"14.9","internal_question_no":"14A.009","question_sort_key":14100900.508,"question_text":"Are the mast heads and their fittings, including but not limited to wire stays, as well as the flood lights, deck lights, emergency lights, and hold lights (if installed), in good working order?","guide_to_inspection":"Wire stays should be inspected, maintained, tightened, and replaced as needed. Some manufacturers sheath wire stays in\nplastic. While the sheathing repels water when new, its effectiveness decreases over time. Deterioration of the plastic coating\ncan allow seawater penetration resulting in corrosion undetectable to external observation.The vessel’s manager should\nestablish a procedure for the regular inspection and maintenance of wire stays sheathed in plastic.\nHold lighting system shall be fully operational and properly maintained. The inspector shall test the lights to make sure the\nlighting system is operative and there is no significant earth on the switch boards.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":213,"source_page_end":213,"raw_source_text":"Are the mast heads and their fittings, including but not limited to wire stays, as well as the flood lights,\ndeck lights, emergency lights, and hold lights (if installed), in good working order? (V)\nGuide to Inspection\nWire stays should be inspected, maintained, tightened, and replaced as needed. Some manufacturers sheath wire stays in\nplastic. While the sheathing repels water when new, its effectiveness decreases over time. Deterioration of the plastic coating\ncan allow seawater penetration resulting in corrosion undetectable to external observation.The vessel’s manager should\nestablish a procedure for the regular inspection and maintenance of wire stays sheathed in plastic.\nHold lighting system shall be fully operational and properly maintained. The inspector shall test the lights to make sure the\nlighting system is operative and there is no significant earth on the switch boards.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"14A","section_number":14,"section_letter":"A","section_title":"General Appearance - Hull and Superstructure","printed_question_no":"14.10","internal_question_no":"14A.010","question_sort_key":14101000.509,"question_text":"Are portable and fixed cargo lights used for illumination of cargo holds inspected regularly and maintained in good condition?","guide_to_inspection":"Record a finding if the lamp holder, drip shield, and shade of portable cargo lights are not non-conductive, do not isolate the\ncrew from electrical shock hazards by the installation of an isolation transformer, or have a voltage greater than 50V AC (1-\n1000Hz) or 120V DC.\nThe human hazard of electric current depends on the intensity and duration of current flow in a specific current path through the\nbody. The technical specification IEC TS 60479-1 comprises the permissible touch currents and the required data to calculate\nthe permissible touch voltages under several conditions (e.g., body resistance, current path, skin moisture (see Parameters for\neffects of electric current) for alternating current and direct current. A touch voltage of 50 V AC (1-1000 Hz) or 120 V DC for long\nshock duration (> 3 s) should not be exceeded in healthy adults otherwise a life-threatening condition may occur.\n“Many bulk carrier / general cargo holds have fixed cargo lights. These can easily ignite combustible cargoes such as grain,\nanimal feed, wood chips, pulp, and paper if they are too close to the light. Self-decomposition of fertiliser has been initiated in\nthis manner. Cargo lights in holds need to be properly isolated before cargo is loaded”.\n“This is best done by removing fuses or other physical links in the electrical circuits so that the lights cannot be switched on\nby mistake. In container ships the lights need to be properly placed so that they do not overheat cargo or other combustibles\nand thus cause damage or fire. Lights in car carriers and ferries are usually fluorescent, which are unlikely to cause ignition.\nNonetheless it makes sense to leave lights switched off when they are not needed, particularly in cargo areas where\ncombustibles are present”\n(A guide to the causes and prevention of cargo fires, 2017)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":214,"source_page_end":214,"raw_source_text":"Are portable and fixed cargo lights used for illumination of cargo holds inspected regularly and\nmaintained in good condition? (V)\nGuide to Inspection\nRecord a finding if the lamp holder, drip shield, and shade of portable cargo lights are not non-conductive, do not isolate the\ncrew from electrical shock hazards by the installation of an isolation transformer, or have a voltage greater than 50V AC (1-\n1000Hz) or 120V DC.\nThe human hazard of electric current depends on the intensity and duration of current flow in a specific current path through the\nbody. The technical specification IEC TS 60479-1 comprises the permissible touch currents and the required data to calculate\nthe permissible touch voltages under several conditions (e.g., body resistance, current path, skin moisture (see Parameters for\neffects of electric current) for alternating current and direct current. A touch voltage of 50 V AC (1-1000 Hz) or 120 V DC for long\nshock duration (> 3 s) should not be exceeded in healthy adults otherwise a life-threatening condition may occur.\n“Many bulk carrier / general cargo holds have fixed cargo lights. These can easily ignite combustible cargoes such as grain,\nanimal feed, wood chips, pulp, and paper if they are too close to the light. Self-decomposition of fertiliser has been initiated in\nthis manner. Cargo lights in holds need to be properly isolated before cargo is loaded”.\n“This is best done by removing fuses or other physical links in the electrical circuits so that the lights cannot be switched on\nby mistake. In container ships the lights need to be properly placed so that they do not overheat cargo or other combustibles\nand thus cause damage or fire. Lights in car carriers and ferries are usually fluorescent, which are unlikely to cause ignition.\nNonetheless it makes sense to leave lights switched off when they are not needed, particularly in cargo areas where\ncombustibles are present”\n(A guide to the causes and prevention of cargo fires, 2017)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"14A","section_number":14,"section_letter":"A","section_title":"General Appearance - Hull and Superstructure","printed_question_no":"14.11","internal_question_no":"14A.011","question_sort_key":14101100.51,"question_text":"Is the condition of electrical equipment including lights,switches,sockets, junction boxes, plugs,conduits, cabling and wiring on weather decks and around the accommodation satisfactory?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":214,"source_page_end":214,"raw_source_text":"Is the condition of electrical equipment including lights,switches,sockets, junction boxes, plugs,conduits,\ncabling and wiring on weather decks and around the accommodation satisfactory?(V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}}]}$RISQQ131$::jsonb AS payload
),
qs AS (
  SELECT id AS question_set_id FROM public.risq_question_sets WHERE question_set_code = 'RISQ_3_2' LIMIT 1
),
input_rows AS (
  SELECT *
  FROM payload p
  CROSS JOIN LATERAL jsonb_to_recordset(p.payload->'questions') AS r(
    section_code text,
    section_number integer,
    section_letter text,
    section_title text,
    printed_question_no text,
    internal_question_no text,
    question_sort_key numeric,
    question_text text,
    guide_to_inspection text,
    answer_type text,
    answer_options jsonb,
    answer_options_inferred boolean,
    inspection_marker text,
    is_removed_question boolean,
    is_active boolean,
    guide_status text,
    source_page_start integer,
    source_page_end integer,
    raw_source_text text,
    metadata jsonb
  )
),
section_lookup AS (
  SELECT s.id AS section_id, s.question_set_id, s.section_code
  FROM public.risq_sections s
  JOIN qs ON qs.question_set_id = s.question_set_id
)
INSERT INTO public.risq_questions (
  question_set_id,
  section_id,
  section_code,
  section_number,
  section_letter,
  section_title,
  printed_question_no,
  internal_question_no,
  question_sort_key,
  question_text,
  guide_to_inspection,
  answer_type,
  answer_options,
  answer_options_inferred,
  inspection_marker,
  is_removed_question,
  is_active,
  guide_status,
  source_page_start,
  source_page_end,
  raw_source_text,
  source_hash,
  metadata,
  created_by,
  updated_by
)
SELECT
  qs.question_set_id,
  sl.section_id,
  i.section_code,
  i.section_number,
  i.section_letter,
  i.section_title,
  i.printed_question_no,
  i.internal_question_no,
  i.question_sort_key,
  i.question_text,
  i.guide_to_inspection,
  i.answer_type,
  i.answer_options,
  COALESCE(i.answer_options_inferred, false),
  COALESCE(i.inspection_marker, ''),
  COALESCE(i.is_removed_question, false),
  COALESCE(i.is_active, true),
  i.guide_status,
  i.source_page_start,
  i.source_page_end,
  i.raw_source_text,
  md5(COALESCE(i.question_text, '') || '|' || COALESCE(i.guide_to_inspection, '') || '|' || COALESCE(i.raw_source_text, '')),
  COALESCE(i.metadata, '{}'::jsonb),
  auth.uid(),
  auth.uid()
FROM input_rows i
CROSS JOIN qs
JOIN section_lookup sl
  ON sl.question_set_id = qs.question_set_id
 AND sl.section_code = i.section_code
ON CONFLICT (question_set_id, internal_question_no)
DO UPDATE SET
  section_id = EXCLUDED.section_id,
  section_code = EXCLUDED.section_code,
  section_number = EXCLUDED.section_number,
  section_letter = EXCLUDED.section_letter,
  section_title = EXCLUDED.section_title,
  printed_question_no = EXCLUDED.printed_question_no,
  question_sort_key = EXCLUDED.question_sort_key,
  question_text = EXCLUDED.question_text,
  guide_to_inspection = EXCLUDED.guide_to_inspection,
  answer_type = EXCLUDED.answer_type,
  answer_options = EXCLUDED.answer_options,
  answer_options_inferred = EXCLUDED.answer_options_inferred,
  inspection_marker = EXCLUDED.inspection_marker,
  is_removed_question = EXCLUDED.is_removed_question,
  is_active = EXCLUDED.is_active,
  guide_status = EXCLUDED.guide_status,
  source_page_start = EXCLUDED.source_page_start,
  source_page_end = EXCLUDED.source_page_end,
  raw_source_text = EXCLUDED.raw_source_text,
  source_hash = EXCLUDED.source_hash,
  metadata = EXCLUDED.metadata,
  updated_by = auth.uid();

COMMIT;

SELECT
  'RISQ question chunk 13/15 imported.' AS result,
  '13A.007' AS chunk_first_question,
  '14A.011' AS chunk_last_question,
  (SELECT COUNT(*) FROM public.risq_questions q JOIN public.risq_question_sets qs ON qs.id = q.question_set_id WHERE qs.question_set_code = 'RISQ_3_2') AS total_questions_imported_so_far;
